function maxLengthBetweenEqualCharacters(s) {
    let result = -1;
    let char_map = {};

    for (let i = 0; i < s.length; ++i) {
        let c = s.charAt(i);
        if (!char_map.hasOwnProperty(c)) {
            char_map[c] = i;
        } else {
            result = Math.max(result, i - char_map[c] - 1);
        }
    }
    return result;
}
